var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……제기랄!","JPN":"……クソ！","ENG":"...Damn it!","TWN":"……該死！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG_02"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"언제까지 여기에 갇혀 있어야 하는 거야?","JPN":"いつまでここに閉じ込められていなきゃならないんだよ？","ENG":"How long do I have to be locked up in here?","TWN":"我們到底要在這裡待到什麼時候？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 미나 양. 흥분을 가라앉히세요.","JPN":"ハハ、ミナさん。落ち着いてください。","ENG":"Ha ha, calm down, Mina.","TWN":"哈哈，米娜，你冷靜一點。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"부사장님이 미나 양을 대기시킨 건 다 이유가 있으실 겁니다.","JPN":"副社長がミナさんを待機させたのにはきっと理由があるはずですよ。","ENG":"The Vice President has her reasons for keeping you on standby.","TWN":"副總會叫你待命一定是有她的理由的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 언제까지 보호만 받으려고 여기 있는 게 아니라고!","JPN":"私はいつまでも守られるためにここにいるわけじゃない！","ENG":"I’m not here to be protected all the time!","TWN":"我之所以會待在這裡，不是要一輩子當溫室的花朵！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다들 목숨을 걸고 싸우고 있잖아? 내 힘도 도움이 될 게 틀림없어.","JPN":"みんな命をかけて戦ってるんでしょ？　私の力もきっと役に立つよ。","ENG":"Everyone’s fighting for their lives! I’m sure that I’ll be of help to them.","TWN":"大家現在都在拼死戰鬥，我的力量一定可以幫上忙的！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배도 이렇게 날 지키고만 있는 것보다 나가서 싸우고 싶지 않아?","JPN":"先輩もこんな風に私を守ってるより、外に出て戦いたくない？","ENG":"Don’t you also want to go out and fight instead of standing guard over me?","TWN":"前輩你也不想只是看著我吧？你難道不想出去戰鬥嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"음, 전 딱히 특별 휴식 시간에 불만이 없습니다만.","JPN":"うむ、僕は別に休憩時間に文句はないんですが。","ENG":"Hmm... I don’t really have any complaints over taking special break time.","TWN":"嗯，我個人是對額外的休息時間沒什麼意見啦。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……안 되겠어.","JPN":"……ダメだ。","ENG":"...That’s it.","TWN":"……不行！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"더 이상은 못 참아! 아무리 부사장님의 말이라고 해도……!","JPN":"もう我慢できない！　いくら副社長の命令だとしても……！","ENG":"I can’t take this anymore! Even if it’s the Vice President’s orders...!","TWN":"我已經忍無可忍！就算是副總說的……！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"제 말이라고 해도, 뭐죠?","JPN":"命令だとしても、何ですか？","ENG":"Even if it’s my orders, what?","TWN":"就算是我說的，然後呢？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"부, 부사장님? 언제 들어온 거야?","JPN":"ふ、副社長？　いつ入ってきたの？","ENG":"V-vice President? When did you come in?","TWN":"副…副總？你什麼時候進來的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고…… 그 무기는 대체?","JPN":"あと……その武器は一体？","ENG":"More than that... What’s that weapon?","TWN":"那個武器是……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"방금 들어왔습니다.","JPN":"今入ってきたばかりです。","ENG":"I just came in.","TWN":"我剛進來，"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그리고 이건 제 전투복입니다. 저도 예전에는 현장에 있었으니까요.","JPN":"そしてこれは私の戦闘服です。昔は私も現場にいましたから。","ENG":"And this is my battle uniform. After all, I was also a field agent when I was younger.","TWN":"這是我的戰鬥服，我以前也曾經在現場執行任務過的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그렇지 않아도 두 사람에게 할 말이 있으니 다들 회의실로 모이시죠.","JPN":"ちょうど二人に話すことがありますので、みんな会議室に集まってください。","ENG":"Anyway, I have something to tell the both of you, so please gather in the conference room.","TWN":"我有話要跟你們說，到會議室集合。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"망아지처럼 날뛰는 건 그 다음에 해도 늦지 않으니까요.","JPN":"暴れまわるのはその後にしても遅くないですから。","ENG":"It won’t be too late to throw a tantrum after you hear me out.","TWN":"你想當脫韁的野馬可以等一下再當。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 알았어……","JPN":"わ、わかったよ……","ENG":"Oh, okay...","TWN":"喔，好……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"드디어 그 두 친구들을 데리고 왔군.","JPN":"ついにあの二人を連れてきたな。","ENG":"You finally brought those two.","TWN":"你終於把他們帶來啦。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그쪽의 최고 전력을 꽁꽁 숨겨두기에 대체 무슨 속셈인가 했지.","JPN":"そちらの最強戦力を隠すから、一体何のつもりなのか気になっていたんだ。","ENG":"I was wondering what you were up to, hiding away your best like that.","TWN":"我還想說你將最厲害的戰力藏起來，到底是在打什麼算盤呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"이제 설명을 들을 수 있겠나?","JPN":"もう説明してくれるのか？","ENG":"Now, will you please explain your plan to me?","TWN":"現在可以請你說明一下嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"미리 말씀드리지 못한 건 사과드리죠.","JPN":"あらかじめお話できなかったことは謝ります。","ENG":"I apologize for not telling you earlier.","TWN":"很抱歉，現在才告訴你。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"하지만 다른 마왕들이 등장하지 못한다는 걸 안 이상, 승부를 걸어볼 때가 되었군요.","JPN":"ですが、他の魔王たちが登場できないことを知った以上、勝負に出る時が来たというわけです。","ENG":"However, now that I know that the other Demon Lords won’t be able to make an appearance, it is time to make our move.","TWN":"不過既然已經知道其他魔王無法出現，那現在就是一決勝負的時候。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"클리포트 게임에서 구 관리국의 작전은 간단했습니다.","JPN":"クリフォトゲームで、旧管理局の作戦は簡単でした。","ENG":"The Old Administration’s strategy for the Qliphoth Game was simple.","TWN":"在逆卡巴拉遊戲中，舊管理局的作戰方式很簡單。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"다른 전대들이 버티는 동안 펜릴 전대가 적진 깊숙히 돌격하여 승부를 내는 겁니다.","JPN":"他の戦隊が持ちこたえている間、フェンリル戦隊が敵陣に深く突撃し、決着をつけるのです。","ENG":"The Fenrir Division would charge deep into hostile territory and strike the decisive blow while the other divisions held off the enemy's advance.","TWN":"就是趁其他戰隊在爭取時間時，由芬里爾戰隊深入敵營決勝負。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"와우, 그건……","JPN":"うわぁ、それは……","ENG":"Wow, that’s...","TWN":"哇喔，這……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"작전도 뭣도 아니군.","JPN":"作戦でもなんでもないな。","ENG":"I wouldn’t call that a strategy.","TWN":"根本不能算是作戰，"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그저 운에 모든 걸 맡기는 특공일 뿐이잖나?","JPN":"ただの運任せの特攻ではないか。","ENG":"But that’s just throwing all of your luck into one assault?","TWN":"只是完全靠運氣的特攻吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"맞습니다. 하지만 현실적으로 가능한 유일한 방법이기도 하죠.","JPN":"そのとおりです。ですが、現実的にできる唯一の方法でもあります。","ENG":"Correct. However, it also happened to be the only realistically viable option.","TWN":"沒錯，但這是現實上唯一可行的方法。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"아군은 열세이고 적들은 강합니다.","JPN":"味方は劣勢であり、敵は強力です。","ENG":"Not only were we outnumbered, but our enemies were powerful.","TWN":"我方處於劣勢，而且敵人很強。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"마왕들에게 우세를 보일 수 있는 전력은 오직 펜릴 전대뿐이었고요.","JPN":"魔王たちに勝る戦力はフェンリル戦隊しかありませんでした。","ENG":"The Fenrir Division was our only force capable of confronting the Demon Lords.","TWN":"面對魔王還能夠居於優勢的戰力，就只有芬里爾戰隊。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그런 상황에서 승리할 방법은 매우 제한적이죠.","JPN":"そんな状況下で勝利する方法はとても制限的です。","ENG":"Our options for victory were very limited in that situation.","TWN":"在這種情況下，可以贏的方法非常有限。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그래서…… 우리가 적의 발을 묶는 동안 코핀 컴퍼니가 적진으로 돌격할 건가?","JPN":"それで……我々が敵の足を引っ張っている間に、コフィンカンパニーが敵陣へ突撃するのか？","ENG":"So... While we keep them occupied, Coffin Company will charge into enemy territory?","TWN":"所以……意思趁我們拖住敵人時，由科芬公司進攻敵營嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"아니요.","JPN":"いいえ。","ENG":"No.","TWN":"不是。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"펜릴 전대가 그런 무모한 작전을 펼칠 수 있었던 건 스승님이 있었기 때문입니다.","JPN":"フェンリル戦隊にそんな無茶な作戦ができたのは師匠がいたからです。","ENG":"The only reason why Fenrir Division was able to pull off such a reckless plan was because of Master.","TWN":"先前芬里爾戰隊之所以能進行如此冒險的作戰，是因為有師父在。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"지금의 전력으로는 무리죠.","JPN":"今の戦力では無理です。","ENG":"It won’t be possible without her, I’m afraid.","TWN":"以現在的戰力而言是辦不到的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그러니…… 역할을 바꾸겠습니다.","JPN":"ですので……役割を変えましょう。","ENG":"Therefore... We need to switch roles.","TWN":"所以……角色要換一下。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"델타세븐이 미나 양과 시윤 군을 데리고 적진을 돌파하십시오.","JPN":"デルタセブンはミナさんとシリュウさんを連れて敵陣を突破してください。","ENG":"Delta Seven will take Mina and Shiyoon and charge into enemy territory.","TWN":"由第七三角洲帶著米娜和時雲攻陷敵營！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"적의 발을 묶는 역할은 제가 맡겠습니다.","JPN":"敵の足を引っ張るのは私がやります。","ENG":"I’ll keep them occupied.","TWN":"我來負責拖住敵人！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"당신이……?","JPN":"君が……？","ENG":"You...?","TWN":"你來……？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"잠깐, 아무리 그래도 혼자서 어떻게 저들을 막고 있겠다는 건가?","JPN":"待て、いくらなんでも一人でどうやって奴らを食い止めるつもりだ？","ENG":"Wait, how do you plan on holding them off by yourself?","TWN":"先等等，就憑你一個人，是要怎麼抵抗他們？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"자랑은 아니지만 이래 봬도 한때는 구 관리국의 에이스라고 불렸던 몸입니다.","JPN":"自慢ではありませんが、こう見えてもかつて旧管理局のエースと呼ばれました。","ENG":"I don’t mean to brag, but I used to be called the Old Administration’s ace.","TWN":"不是我在說，別看我這樣，想當初我也是舊管理局的王牌。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"시간을 끄는 정도라면 충분하죠.","JPN":"時間を稼ぐくらいなら十分でしょう。","ENG":"When it comes to buying time, I should be sufficient.","TWN":"拖個時間而已，我還辦得到。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"죽을지도 모르네. 아니, 반드시 죽겠지.","JPN":"死ぬかもしれない。いや、必ず死ぬだろう。","ENG":"You might die. No, you will die.","TWN":"你很可能會賠上性命，不，是一定會死。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"상관없습니다.","JPN":"構いません。","ENG":"It doesn’t matter.","TWN":"無所謂。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그날 이후로…… 전 이미 한 번은 죽었다고 생각하고 있습니다.","JPN":"あの日以来……私は一度死んだと思っています。","ENG":"Ever since that day... I’ve considered myself to have died once already.","TWN":"自從那天後……我就已經死過一次了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"하지만 그래도 두 번 죽고 싶지는 않으니까요.","JPN":"でも二度は死にたくありませんから。","ENG":"Nevertheless, I don’t want to die a second time.","TWN":"不過我也沒有想死第二次啦。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"너무 걱정 마시죠. 저 혼자라면 반드시 살아남을 수 있습니다.","JPN":"あまり心配しないでください。私一人でなら必ず生き残ることができます。","ENG":"Don’t worry too much. I’ll be able to survive on my own.","TWN":"不用擔心我，我自己一定能活下來的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그리고 현재로선 이게 게임에서 승리할 가능성이 가장 큰 방법입니다.","JPN":"そして現時点ではこれがゲームで勝利する可能性がもっとも高い方法です。","ENG":"Also, this is our biggest chance for achieving victory in the current situation.","TWN":"而且這是現在最有機會能夠在遊戲中獲勝的方法。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"난 구 관리국의 방식에 대해서 동의하지 않아.","JPN":"私は旧管理局のやり方には賛同できない。","ENG":"I don’t agree with the methods of the Old Administration.","TWN":"我不認同舊管理局的方式。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"인류가 스스로의 힘으로 살아갈 수 있어야 한다는 신념도 바뀌지 않네.","JPN":"人類が自らの力で生き抜くべきという信念も変わらない。","ENG":"My conviction that humanity must learn to survive on its own has not changed either.","TWN":"而且我認為人類應該靠自己的力量活下去，這個信念現在也沒有改變。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"하지만 적어도…… 그곳에서 싸워온 자들에겐 경의를 표하지.","JPN":"だが少なくとも……そこで戦ってきた者たちには敬意を表しよう。","ENG":"However, at the very least... I offer my respects to those who have fought as part of it.","TWN":"不過至少……我要對在那個地方奮戰過的人表達敬意。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"자네처럼.","JPN":"君のようにな。","ENG":"Just like you.","TWN":"包括你在內。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"……감사합니다.","JPN":"……ありがとうございます。","ENG":"...Thank you.","TWN":"……謝謝。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"저 역시 지난 20년간 인간의 세계를 지켜오신 분들께 감사하다는 말을 드리고 싶군요.","JPN":"私も20年間人間の世界を守ってきた皆さんに感謝の言葉を送りたいです。","ENG":"I, too, would like to offer my gratitude to those who have protected humanity for the past 20 years.","TWN":"我也想對這20年來一直守護人類世界的人道謝。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"살아서 돌아오게 되면 저희 회사에 한 번 오시죠.","JPN":"生きて帰ったら、私の会社に一度お越しください。","ENG":"If you manage to return alive, please visit our company.","TWN":"要是能活著回來，歡迎你到我們公司一趟。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"시원한 맥주라도 한 잔 사겠습니다.","JPN":"冷たいビールでも一杯おごりましょう。","ENG":"I'll buy you a beer.","TWN":"我請你喝杯冰涼的啤酒。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"아니, 나 같은 공무원은 사기업에서 접대를 받으면 곤란해.","JPN":"いや、私のような公務員は私企業から接待を受けては困る。","ENG":"No, I’ll be put in an awkward position if I receive such treatment from a private company.","TWN":"不，身為公務員人，是不能接受私人企業的招待的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그러니 내가 한 잔 사도록 하지.","JPN":"だから私が一杯おごるとしよう。","ENG":"As such, I’ll buy the first round.","TWN":"所以換我請你喝一杯吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"맥주보다는 소주로. 그라운드 원에는 그런 술도 있다고 하던데?","JPN":"ビールよりは焼酎でな。グラウンド・ワンにはそのような酒もあると聞いたのだが。","ENG":"And soju instead of beer. I heard that they sell this drink at Ground One, no?","TWN":"而且不喝啤酒，喝燒酒，我聽說G1有那種酒？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그거 좋네요.","JPN":"それはいいですね。","ENG":"Sounds good.","TWN":"我喜歡。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"아 참, 말씀드리는 걸 깜박했군요.","JPN":"そうでした。お伝えするのを忘れていましたね。","ENG":"Oh, before you go, I almost forgot to tell you.","TWN":"對了，差點忘了正事。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"코핀 함에 실어 둔 화물이 하나 있습니다. 그걸 꼭 가져가십시오.","JPN":"コフィンの艦船に積載しておいた貨物があります。それをぜひお持ちください。","ENG":"In the Coffin, there is a cargo prepared. Please take that with you.","TWN":"科芬艦上有裝載一樣貨物，請你務必要帶走。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"화물?","JPN":"貨物？","ENG":"A cargo?","TWN":"貨物？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"네. 만약 클리파 차원에 돌입하는데 성공한다면……","JPN":"はい。もしクリファ次元に突入することに成功したら……","ENG":"Yes. If you happen to succeed in reaching the Qlipha Dimension...","TWN":"是的，若是成功進到逆卡巴拉次元……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"반드시 도움이 될 겁니다.","JPN":"必ず役に立つでしょう。","ENG":"It will surely be of great use to you.","TWN":"相信會有幫助的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전하, 공간균열이 사라지고 있습니다.","JPN":"殿下、空間亀裂が消えていきます。","ENG":"Your Highness, the space rift is starting to close.","TWN":"殿下，空間裂縫正在消失中。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L43_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"벌써? 생각보다 이르군.","JPN":"もう？　思ったより早いな。","ENG":"Already? That’s earlier than expected.","TWN":"這麼快？比我預期的還快呢。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마르티네즈 공이 결판을 낸 것인가…… 아니면 적들이 반격에 성공한 것인가?","JPN":"マルチネス公が決着をつけたのか……それとも敵が反撃に成功したのか。","ENG":"Perhaps Marquise Martinez has prevailed... Or the enemy has succeeded in their Marquiseeroffensive?","TWN":"馬汀尼茲侯爵會定出勝負嗎…… 還是敵人會反擊成功呢？"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"어느 쪽이든 기대되는군. 좋은 흐름이다.","JPN":"どちらにせよ楽しみだな。いい流れだ。","ENG":"Whichever the case, I look forward to it. I like where this is going.","TWN":"二者都很令人期待呢，這個劇情走向很不錯。"},"stage":{"bg":"MS_903","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"저건……! 전하, 적의 기함 엔터프라이즈입니다!","JPN":"あれは……！　殿下、敵の旗艦、エンタープライズです！","ENG":"Isn’t that...?! Your Highness, it’s the enemy flagship, the Enterprise!","TWN":"那是……！殿下，是敵人的艦船 企業號！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"공간균열을 일부러 무너트린 모양이군요. 빠른 속도로 다가오고 있습니다.","JPN":"空間亀裂をわざわざ崩したようですね。早い速度で近づいてきています。","ENG":"It seems that they have collapsed the space rift early on purpose. It’s approaching us at high speed.","TWN":"看來是故意破壞空間裂縫的，艦船正快速朝這裡移動。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"저 속도라면…… 저희를 지나쳐서 후방으로 돌입하려는 의도인 것 같군요.","JPN":"あの速度なら……私たちを通り過ぎて後方へと突入するつもりのようですね。","ENG":"Considering their speed... Their intentions seem to be to fly past us and get break through our lines.","TWN":"照那個速度……似乎是打算直接略過我們襲擊後方。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"호오, 승부를 걸기로 했나 보군.","JPN":"ほう、勝負をかけることにしたようだな。","ENG":"So, they’ve decided to play their hand.","TWN":"呵，是打算一決勝負嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하긴 두 마왕의 군세에 퇴로가 막혔으니 별다른 방법이 없었겠지.","JPN":"まあ、二人の魔王の軍勢に退路を断たれたのだ。他の方法はあるまい。","ENG":"I don’t blame them. With two Demon Lords blocking their exit, they probably don’t have any other choice.","TWN":"也是，畢竟兩個魔王的勢力堵住退路，也沒什麼其他辦法。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"허나 그리 쉽게 우리 기사단을 돌파할 수 있을 거라 믿는 건…… 오만이 아닌가?","JPN":"だが、そう容易く我々の騎士団を突破できると信ずるのは……傲慢ではないか？","ENG":"However, it’s arrogant of them to think that they can break through our lines so easily.","TWN":"不過竟然認為可以輕易突破我們騎士團……會不會太有自信？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"마르티네즈 공에게 전령을 보내라!","JPN":"マルチネス公に伝令を送れ！","ENG":"Send a message to Marquise Martinez!","TWN":"向馬汀尼茲侯爵傳令！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"놈들이 탈출하지 못하도록 퇴로를 차단하도록!","JPN":"奴らが脱出できないように退路を遮断しろ！","ENG":"Tell her to cut off their exit path so that they won’t be able to escape!","TWN":"切斷敵人的退路，一個也別想逃！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"전방에서 놈들의 돌격을 막는 건 내가 직접 나서겠다!","JPN":"私が直接前方から奴らの突撃を止めるぞ！","ENG":"I’ll personally lead our forces to block their charge forward!","TWN":"由我親自上陣，在前方阻止敵人的襲擊！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"미안하지만 그렇게는 안 될 겁니다.","JPN":"すみませんが、そうはいきません。","ENG":"Sorry, but I will not allow that to happen.","TWN":"不好意思，可能沒辦法喔。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L13_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저 여자는……?","JPN":"あの女は……？","ENG":"That woman...","TWN":"那女人是……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"피하십시오, 전하!","JPN":"お避けください、殿下！","ENG":"Look out, Your Highness!","TWN":"殿下，快躲開！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"큿……!","JPN":"くっ……！","ENG":"Erck...!","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"샬롯 경, 괜찮은가?","JPN":"シャーロット卿、大丈夫か？","ENG":"Dame Carlota, are you okay?","TWN":"夏洛特卿，你沒事吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……번개의 전사를 상대하던 중에 기습적인 공격을 받았을 뿐이다.","JPN":"……稲妻の戦士を相手する途中、奇襲攻撃を受けただけだ。","ENG":"...I was merely ambushed by the enemy while facing the Lightning Warrior.","TWN":"……就只是在和閃電戰士交手時突然受到攻擊而已。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"이 정도로…… 전하에게 가는 길을 열어줄 수는 없어!","JPN":"この程度で……殿下への道を開けるわけにはいかない！","ENG":"That... will not be enough to get to His Highness!","TWN":"光是這樣……是無法替殿下開路的！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"물러나라, 마르티네즈 공.","JPN":"下がれ、マルチネス公。","ENG":"Stand down, Marquise Martinez..","TWN":"馬汀尼茲侯爵，你退下。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L26_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"저, 전하?","JPN":"で、殿下？","ENG":"Y-your Highness?","TWN":"殿…殿下？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"아직 승부는 나지 않았습니다!","JPN":"まだ勝負は終わっておりません！","ENG":"My fight has not concluded yet!","TWN":"還沒分出勝負！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"전하를 위협하는 자들은 제 목숨을 걸고……","JPN":"殿下を脅かす者は私の命をかけて……","ENG":"Upon my life, I’ll destroy those who threaten Your─","TWN":"我會拼命除掉威脅殿下的人……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그런 것이 아니다. 마르티네즈 공.","JPN":"そういう意味ではないぞ。マルチネス公。","ENG":"That is not my intention, Marquise Martinez..","TWN":"不需要這樣，馬汀尼茲侯爵。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대는 맡은 역할을 잘 수행했다.","JPN":"そなたは任務を見事遂行した。","ENG":"You have played your part well.","TWN":"你已經善盡你的職責，"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 이제는 내게도 여흥을 누릴 기회를 양보해야 하지 않겠는가?","JPN":"だからもう私にも余興を楽しむ機会を譲るべきであろう。","ENG":"As such, will you allow me to entertain myself now?","TWN":"現在不能讓我有點餘興時間嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……알겠습니다, 전하.","JPN":"……かしこまりました、殿下。","ENG":"...I understand, Your Highness.","TWN":"……是，殿下。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"자아, 이제 그대의 상대는 나, 제국의 황태자 클라레스 엘 아르카데나다.","JPN":"さあ、これよりそなたの相手は私、帝国の皇太子たるクラレス・エル・アルカデナだ。","ENG":"Now, I, Clareth El Arcadena, Crown Prince of the Empire, will be your opponent.","TWN":"來吧，現在你的對手是我，帝國的皇太子 克拉雷斯 耶魯 艾爾卡特納。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"허나 무모하지 않은가? 늑대의 문장을 지닌 자여.","JPN":"だが、無茶ではないか？　オオカミの紋章を持つ者よ。","ENG":"However, is this not a reckless act, Warrior with the Seal of the Wolf?","TWN":"不過有狼紋的女人，你不會太莽撞嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"이곳에는 나뿐만 아니라 구원 기사단과 제국의 수많은 정예들이 포진해 있다.","JPN":"ここには私だけでなく、救世騎士団と数多くの帝国精鋭が陣取っているぞ。","ENG":"Not only myself, but the Knights of Redemption and countless elite imperial troops are in position here.","TWN":"這裡不是只有我，還有救贖騎士團和眾多帝國的精兵。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대가 아무리 뛰어난 무인이라 해도 홀로 온 이상 살아서 돌아가지는 못 할 터인데?","JPN":"そなたがいくら優れた武人であっても、一人で来た以上は生きては帰れないはずだが？","ENG":"No matter how impressive of a warrior you may be, it’ll be difficult for you to return alive by yourself.","TWN":"就算你武功再怎麼高強，當你選擇獨自前來時，就已經定下無法活著回去的結局。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저 보잘 것 없는 배에 그대의 생명과 희망을 모두 걸어도 후회하지 않을 것인가?","JPN":"あのしがない船にそなたの命と希望をすべてかけても後悔しないというのか？","ENG":"Will you not regret betting your life and hope on that pathetic ship?","TWN":"把你的性命和希望全押那艘破船上，你不後悔嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"……늑대의 문장을 알아본다면, 대답은 알고 있겠지?","JPN":"……オオカミの紋章がわかるのなら、答えは知ってるだろう？","ENG":"...If you recognize the Seal of the Wolf, then you already know my answer.","TWN":"……既然你認得出狼紋，那應該知道我的回答吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"그리고 얕보지 마라. 네헤모트의 사도.","JPN":"それから見くびるな。ネヘモトの使徒。","ENG":"Also, you underestimate me, Apostle of Nehemoth.","TWN":"還有，你少瞧不起人，貝赫莫特的使徒。"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"나는 세상의 선택을 받지도, 신들의 혈통을 가진 것도 아닌 평범한 인간이지만……","JPN":"私は世界に選ばれても、神々の血統を持ってもいない普通の人間だが……","ENG":"I may be a mere human who was neither chosen by the world or carries the blood of a god in my veins...","TWN":"雖然我不是天選之人，也沒有神的血統，就只是一個平凡人……"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"세상의 앞에서도, 신들의 앞에서도 물러나 본 적 없는.","JPN":"世界の前でも、神々の前でも退いたことのない。","ENG":"But I have never faltered in the face of the world or the face of a god.","TWN":"但無論是面對世界，或是面對神，我可從未退卻過，"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_WING_NULL_NULL","text":{"KOREA":"늑대의 긍지를 가진 자다.","JPN":"狼の誇りを持つ者だ。","ENG":"For I am the one with the Wolf's Pride.","TWN":"我是有狼的自負之人！"},"stage":{"bg":"SKY_SUNSET","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_WING_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"하하, 멋진 대답이다.","JPN":"はは、素晴らしい返答だ。","ENG":"Ha ha, that was an honorable reply.","TWN":"哈哈，真是帥氣的回答。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그대의 긍지에 걸고, 전력으로 상대해 주마!","JPN":"そなたの誇りにかけて、全力で相手してやろう！","ENG":"Out of respect for your pride, I’ll face you with everything that I have!","TWN":"那就賭上你的自負，毫無保留地出招吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"THEMA_CA_ADMIN_LEE_SUYEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};